767	        BinOpr::BXor => (lua_code::opcodes::OpCode::BXor, lua_types::tagmethod::TagMethod::Bxor),
768	        BinOpr::Shl  => (lua_code::opcodes::OpCode::Shl,  lua_types::tagmethod::TagMethod::Shl),
769	        BinOpr::Shr  => (lua_code::opcodes::OpCode::Shr,  lua_types::tagmethod::TagMethod::Shr),
770	        _ => todo!(
771	            "phase-b: cg_posfix_fold non-foldable binop {:?} ({:?} {:?})",
772	            op, e1.k, e2.k
773	        ),
774	    };
775	
776	    cg_discharge_vars(fs, line, e1)?;
777	    cg_discharge_vars(fs, line, e2)?;
778	    let v2 = cg_exp_to_any_reg(fs, line, e2)?;
779	    let v1 = cg_exp_to_any_reg(fs, line, e1)?;
780	
781	    let inst = lua_code::opcodes::Instruction::abck(opcode, 0, v1 as u32, v2 as u32, 0);
782	    let pc = emit_inst(fs, line, inst);
783	    cg_free_exps(fs, e1, e2);
784	    e1.u.info = pc;
785	    e1.k = ExprKind::Reloc;
786	
