788	        lua_code::opcodes::OpCode::MmBin,
789	        v1 as u32,
790	        v2 as u32,
791	        event as u32,
792	        0,
793	    );
794	    emit_inst(fs, line, mm_inst);
795	    Ok(())
796	}
